import React, { memo, useEffect } from 'react'
import type { FC, ReactNode } from 'react'
import { Table, Input, Box, Typography, IconButton, Chip } from '@mui/joy'
import { Checkbox } from '@mui/joy'
import ChipDelete from '@mui/joy/ChipDelete'
import SearchIcon from '@mui/icons-material/Search'
import BarChartIcon from '@mui/icons-material/BarChart'
import RefreshIcon from '@mui/icons-material/Refresh'
import ExpandLessIcon from '@mui/icons-material/ExpandLess'
import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import ArrowDownwardIcon from '@mui/icons-material/ArrowDownward'
import UnfoldMoreIcon from '@mui/icons-material/UnfoldMore'
import UnfoldLessIcon from '@mui/icons-material/UnfoldLess'

interface Iprops {
  children?: ReactNode
  name: string
  title: string
  expanded: boolean
  resetFilters: boolean
  data: IBMSelectorItem[]
  onCallBack?: (title, data: IBMSelectorItem[]) => void
}

export interface IBMSelectorItem {
  id: string | number
  name: string
  number: number
  percentage: number
}

const BMSelectorItem: FC<Iprops> = (props) => {
  const { name, title, expanded: initialExpanded, resetFilters, data: initialData, onCallBack } = props
  const [expanded, setExpanded] = React.useState(initialExpanded)
  const [unfold, setUnfold] = React.useState(false)
  const [searchTerm, setSearchTerm] = React.useState('')
  const [viewMode, setViewMode] = React.useState('chart')
  const [showSearch, setShowSearch] = React.useState(initialExpanded)
  const [sortField, setSortField] = React.useState('number')
  const [sortAsc, setSortAsc] = React.useState(false)
  const [selectedItems, setSelectedItems] = React.useState<any[]>([])
  const searchInputRef = React.useRef<HTMLInputElement>(null)

  const handleSort = (field) => {
    if (sortField === field) {
      setSortAsc(!sortAsc)
    } else {
      setSortField(field)
      setSortAsc(true)
    }
  }

  const toggleSelection = (name) => {
    setSelectedItems((prev) => (prev.includes(name) ? prev.filter((item) => item !== name) : [...prev, name]))
  }

  const clearAllSelections = () => {
    setSelectedItems([])
    setSearchTerm('')
  }

  // 过滤数据（适用于表格 & 选中项）
  const filteredData = initialData
    .filter((row) => row.name.toLowerCase().includes(searchTerm.toLowerCase()))
    .sort((a, b) => {
      if (sortField === 'name') {
        return sortAsc ? a.name.localeCompare(b.name) : b.name.localeCompare(a.name)
      }
      return sortAsc ? a.number - b.number : b.number - a.number
    })

  const filteredSelectedItems = selectedItems.filter((name) => name.toLowerCase().includes(searchTerm.toLowerCase()))

  useEffect(() => {
    onCallBack && onCallBack(name, selectedItems)
  }, [selectedItems])

  useEffect(() => {
    setSelectedItems([])
  }, [resetFilters])

  useEffect(() => {
    console.log('expandedAll-initialExpanded', initialExpanded, expanded)
    setShowSearch(initialExpanded)
    setExpanded(initialExpanded)
  }, [initialExpanded])

  useEffect(() => {
    searchInputRef.current?.focus()
  }, [])

  return (
    <div style={{ padding: '5px' }}>
      <Box
        sx={{
          width: 260,
          borderRadius: '8px',
          overflow: 'hidden',
          border: '1px solid #ddd',
          bgcolor: '#fff',
          paddingTop: 0
        }}>
        {/* Header */}
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            height: '32px',
            p: '4px 0px',
            bgcolor: '#2f3542',
            color: '#fff'
          }}>
          <IconButton
            onClick={() => {
              setShowSearch(!expanded)
              setExpanded(!expanded)
            }}
            size='sm'
            sx={{
              '--Icon-color': '#a4b0be',
              '&:hover': { '--Icon-color': 'white', bgcolor: '#2f3542' },
              '&:active': { '--Icon-color': 'white', bgcolor: '#2f3542' }
            }}>
            {expanded ? <ExpandLessIcon /> : <ExpandMoreIcon />}
          </IconButton>
          <Typography fontWeight='bold' sx={{ flexGrow: 1, color: 'white', fontSize: '14px' }}>
            {title}
          </Typography>
          <IconButton
            onClick={() => {
              if (expanded || selectedItems.length > 0) setShowSearch(!showSearch)
              setTimeout(() => {
                searchInputRef.current?.focus()
              }, 1000)
            }}
            size='sm'
            sx={{
              '--Icon-color': showSearch ? 'white' : '#a4b0be',
              '&:hover': { '--Icon-color': 'white', bgcolor: '#2f3542' },
              '&:active': { '--Icon-color': 'white', bgcolor: '#2f3542' }
            }}>
            <SearchIcon />
          </IconButton>
          <IconButton
            onClick={() => {
              if (expanded || selectedItems.length > 0) setViewMode(viewMode === 'table' ? 'chart' : 'table')
            }}
            size='sm'
            sx={{
              '--Icon-color': viewMode === 'chart' ? 'white' : '#a4b0be',
              '&:hover': { '--Icon-color': 'white', bgcolor: '#2f3542' },
              '&:active': { '--Icon-color': 'white', bgcolor: '#2f3542' }
            }}>
            <BarChartIcon />
          </IconButton>
          <IconButton
            onClick={() => {
              if (unfold) {
                setUnfold(false)
              } else {
                setExpanded(true)
                setUnfold(true)
              }
            }}
            size='sm'
            sx={{
              '--Icon-color': '#a4b0be',
              '&:hover': { '--Icon-color': 'white', bgcolor: '#2f3542' },
              '&:active': { '--Icon-color': 'white', bgcolor: '#2f3542' }
            }}>
            {unfold ? <UnfoldLessIcon /> : <UnfoldMoreIcon />}
          </IconButton>
          <IconButton
            onClick={() => {
              setSearchTerm('')
              setViewMode('table')
              setSortField('number')
              setSortAsc(false)
              clearAllSelections()
            }}
            size='sm'
            sx={{
              '--Icon-color': filteredSelectedItems.length > 0 ? '#ff4757' : '#a4b0be',
              '&:hover': { '--Icon-color': 'white', bgcolor: '#2f3542' },
              '&:active': { '--Icon-color': 'white', bgcolor: '#2f3542' }
            }}>
            <RefreshIcon />
          </IconButton>
        </Box>

        {/* 搜索框 */}
        {showSearch && (
          <Box sx={{ p: 1, paddingBottom: '1px' }}>
            <Input
              ref={searchInputRef}
              size='sm'
              sx={{
                '--Input-minHeight': '26px',
                '--Input-focusedThickness': '1px'
              }}
              placeholder='Search...'
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              fullWidth
            />
          </Box>
        )}

        {/* 表格内容 */}
        {expanded && (
          <Box
            sx={(theme) => ({
              padding: 1,
              paddingTop: 0,
              height: unfold ? '100%' : 120,
              overflowY: 'scroll',
              background: `linear-gradient(${theme.vars.palette.background.surface} 30%, rgba(255, 255, 255, 0)),
            linear-gradient(rgba(255, 255, 255, 0), ${theme.vars.palette.background.surface} 70%) 0 100%,
            radial-gradient(
              farthest-side at 50% 0,
              rgba(0, 0, 0, 0.12),
              rgba(0, 0, 0, 0)
            ),
            radial-gradient(
                farthest-side at 50% 100%,
                rgba(0, 0, 0, 0.12),
                rgba(0, 0, 0, 0)
              )
              0 100%`,
              backgroundSize: `100% ${theme.spacing(2)}, 100% ${theme.spacing(2)}, 100% ${theme.spacing(
                0.5
              )}, 100% ${theme.spacing(0.5)}`,
              backgroundRepeat: 'no-repeat',
              backgroundAttachment: 'local, local, scroll, scroll',
              backgroundPosition: `0 31px, 0 100%, 0 31px, 0 100%`,
              backgroundColor: 'background.surface'
            })}>
            <Table
              stickyHeader
              size='sm'
              sx={{
                fontSize: '12px',
                borderCollapse: 'collapse',
                width: '100%',
                '& thead th': {
                  height: '18px',
                  lineHeight: '18px',
                  borderBottom: '0px solid #ffffff'
                },
                '& tbody tr': {
                  height: '18px',
                  lineHeight: '18px',
                  cursor: 'pointer',
                  position: 'relative',
                  '&:hover': {
                    bgcolor: '#f0f0f0' // 悬停时高亮
                  }
                },
                '& tbody td': {
                  padding: '1px 0.25rem 1px 0.25rem',
                  height: '18px',
                  lineHeight: '18px',
                  borderBottom: '0px solid #ffffff'
                },
                '& .selected': {
                  bgcolor: '#d0e0ff' // 选中行高亮
                }
              }}>
              <thead>
                <tr>
                  <th colSpan={2} style={{ padding: '6px 0', fontSize: '14px', textAlign: 'left' }}>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <Box
                        onClick={() => handleSort('name')}
                        sx={{ cursor: 'pointer', display: 'flex', alignItems: 'center', fontSize: '12px' }}>
                        Name
                        <ArrowDownwardIcon
                          sx={{
                            fontSize: '12px',
                            marginLeft: '4px',
                            transition: 'transform 0.2s',
                            transform: sortField === 'name' && !sortAsc ? 'rotate(180deg)' : 'rotate(0deg)'
                          }}
                        />
                      </Box>
                      <Box
                        onClick={() => handleSort('number')}
                        sx={{ cursor: 'pointer', display: 'flex', alignItems: 'center', fontSize: '12px' }}>
                        Files
                        <ArrowDownwardIcon
                          sx={{
                            fontSize: '12px',
                            marginLeft: '4px',
                            transition: 'transform 0.2s',
                            transform: sortField === 'number' && !sortAsc ? 'rotate(180deg)' : 'rotate(0deg)'
                          }}
                        />
                      </Box>
                    </Box>
                  </th>
                </tr>
              </thead>
              <tbody>
                {filteredData.map((row) => (
                  <tr
                    key={row.name}
                    className={selectedItems.includes(row.name) ? 'selected' : ''}
                    onClick={() => toggleSelection(row.name)}
                    style={{ position: 'relative' }}>
                    <td colSpan={2} style={{ position: 'relative', padding: '0px' }}>
                      <Box
                        sx={{
                          position: 'absolute',
                          top: 0,
                          left: 0,
                          width: `${viewMode === 'chart' ? row.percentage : 0}%`,
                          height: '100%',
                          bgcolor: '#dfe4ea',
                          zIndex: 0
                        }}
                      />
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', position: 'relative', zIndex: 1 }}>
                        <span>{row.name}</span>
                        <span style={{ textAlign: 'right' }}>{row.number}</span>
                      </Box>
                    </td>
                  </tr>
                ))}
              </tbody>
            </Table>
          </Box>
        )}

        {/* 选中项显示 */}
        {filteredSelectedItems.length > 0 && (
          <Box sx={{ p: 1, display: 'flex', flexWrap: 'wrap', gap: 0.5 }}>
            {filteredSelectedItems.map((item) => (
              <Chip
                key={item}
                variant='outlined'
                size='sm'
                sx={{
                  fontSize: '11px',
                  padding: '1px 6px',
                  height: '16px'
                }}
                // endDecorator={<ChipDelete onDelete={() => toggleSelection(item)} />}>
                onClick={() => toggleSelection(item)}>
                {item}
              </Chip>
            ))}
            <Chip color='danger' variant='soft' size='sm' onClick={clearAllSelections}>
              Clear
            </Chip>
          </Box>
        )}
      </Box>
    </div>
  )
}

export default memo(BMSelectorItem)
